package com.hospital.management.model;
import java.time.LocalDateTime;import java.util.Objects;
/** Hospital department domain model. */
public class Department {private Long departmentId;private String departmentName;private String description;private String location;private String status;private LocalDateTime createdAt;private LocalDateTime updatedAt;
 public Department(){}public Department(Long id,String name,String description,String location,String status){departmentId=id;departmentName=name;this.description=description;this.location=location;this.status=status;}
 public Long getDepartmentId(){return departmentId;}public void setDepartmentId(Long v){departmentId=v;}public String getDepartmentName(){return departmentName;}public void setDepartmentName(String v){departmentName=v;}public String getDescription(){return description;}public void setDescription(String v){description=v;}public String getLocation(){return location;}public void setLocation(String v){location=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}public LocalDateTime getUpdatedAt(){return updatedAt;}public void setUpdatedAt(LocalDateTime v){updatedAt=v;}
 public boolean equals(Object o){return this==o||(o instanceof Department d&&departmentId!=null&&departmentId.equals(d.departmentId));}public int hashCode(){return Objects.hashCode(departmentId);}public String toString(){return "Department{id="+departmentId+", name='"+departmentName+"', status='"+status+"'}";}}
